const d = new Date();
d.setDate(d.getDate() + 1);
const y = d.getFullYear();
const m = String(d.getMonth() + 1).padStart(2, '0');
const day = String(d.getDate()).padStart(2, '0');
return [{ json: { tomorrow: `${y}-${m}-${day}` } }];

// Agrupa múltiplos agendamentos do mesmo cliente em um único item
const items = $input.all();
const grouped = {};

for (const item of items) {
  const phone = item.json.Telefone;
  if (!grouped[phone]) {
    grouped[phone] = {
      Telefone: phone,
      v_cliente: item.json.v_cliente,
      appointments: []
    };
  }
  grouped[phone].appointments.push({
    id: item.json.id,
    start: item.json.start,
    id_servico: String(item.json.id_servico),
    id_barbeiro: String(item.json.id_barbeiro)
  });
}

const result = Object.values(grouped).map(client => {
  client.appointments.sort((a, b) => a.start.localeCompare(b.start));
  client.appointment_ids = client.appointments.map(a => a.id).join(',');
  return { json: client };
});

return result;

// $json = objeto do cliente (de 'Agrupar por Cliente')
// $('Buscar Serviços MCP').first().json.services = array de serviços buscado 1x no início
const client = $json;
const svcs = $('Buscar Serviços MCP').first().json.services || [];

const serviceMap = {};
for (const svc of svcs) {
  if (svc.id != null && svc.name) serviceMap[String(svc.id)] = svc.name;
}

const emojis = ['1️⃣', '2️⃣', '3️⃣', '4️⃣', '5️⃣'];
const apptLines = client.appointments.map((appt, i) => {
  const serviceName = serviceMap[appt.id_servico] || `Serviço ${appt.id_servico}`;
  const d = new Date(appt.start);
  const timeStr = d.toLocaleTimeString('pt-BR', {
    hour: '2-digit',
    minute: '2-digit',
    timeZone: 'America/Sao_Paulo'
  });
  return `${emojis[i] || '•'} *${serviceName}* — ${timeStr}`;
});

const plural = client.appointments.length > 1;
const header = plural
  ? `Passando para confirmar seus *${client.appointments.length} agendamentos* de amanhã na *Don Aveiro* ✂️`
  : `Passando para confirmar seu agendamento de amanhã na *Don Aveiro* ✂️`;

const msg = `Olá, *${client.v_cliente}*! 👋\n\n${header}\n\n${apptLines.join('\n')}\n\nConfirme sua presença respondendo:\n✅ *CONFIRMO* — presença confirmada\n❌ *CANCELAR* — se não puder comparecer\n\nCaso cancele, podemos remarcar direto aqui no chat! 😊`;

return [{
  json: {
    Telefone: client.Telefone,
    v_cliente: client.v_cliente,
    chatId: `${client.Telefone}@c.us`,
    text: msg,
    appointment_ids: client.appointment_ids
  }
}];
